import React, { useState } from 'react';

const dev = () => {
  const images = ["image1.jpg", "image2.jpg", "image3.jpg"]; // Replace with the actual image URLs or file names
  const [imageIndex, setImageIndex] = useState(0);
  
  const showNextImage = () => {
    setImageIndex((prevIndex) => (prevIndex + 1) % images.length);
  };
  
  return (
    <div className="homepic">
      <img src={images[imageIndex]} alt="" className="logo-img" />
      <button onClick={showNextImage}>Next Image</button>
    </div>
  );
};

export default dev;
